      "content": "// src/modules/projects/service.js
const { randomUUID } = require('node:crypto');
const projectsStore = [];

async function getAllProjects() {
  return projectsStore.slice();
}

async function createProject(name) {
  if (projectsStore.some(project => project.name === name)) {
    return null; // Return null for duplicate project name
  }
  const project = { id: randomUUID(), name };
  projectsStore.push(project);
  return project;
}

async function getProjectById(id) {
  const project = projectsStore.find(p => p.id === id);
  if (!project) {
    return null; // Return null for project not found
  }
  return project;
}

module.exports = { getAllProjects, createProject, getProjectById };
